checker_dsl:
EXISTS (`left shift expression LSE`) {
  AND {
    (`the type of the left operand of LSE is IT`),
    (`the right operand of LSE is a compile-time constant expression and its integer value is V`),
    EXISTS (`integer bit width W`) {
      OR {
        AND {
          (`IT has the name "long"`),
          (`W is 64`)
        },
        AND {
          NOT { (`IT has the name "long"`) },
          NOT { (`IT has the name "Long"`) },
          (`W is 32`)
        }
      }
    },
    (`V is greater than or equal to W`)
  }
}
